1	interface Item {
2	  type: string;
3	}
4	
5	interface Step {
6	  type: string;
7	  items: Item[];
8	}
9	
10	interface Scenario {
11	  customer: { years: number };
12	  steps: Step[];
13	}
14	
15	interface Result {
16	  premium: number;
17	}
18	
19	interface ScenarioOutput {
20	  results: Result[];
21	}
22	
23	const PROCESSING_FEE = 5;
24	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
25	
26	const BASE_PREMIUMS: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	};
30	
31	export function processScenario(scenario: Scenario): ScenarioOutput {
32	  const step = scenario.steps[0];
33	  if (step.items.length === 0) {
34	    return { results: [{ premium: PROCESSING_FEE }] };
35	  }
36	  const basePremium = BASE_PREMIUMS[step.items[0].type];
37	  const premium = basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE + PROCESSING_FEE;
38	  return { results: [{ premium }] };
39	}
